
-- Full Kaltim Questionnaire Seed
INSERT INTO public.questionnaires (title, description, questions, assigned_surveyors, is_active)
VALUES (
    'Survei Persepsi Masyarakat Menjelang Pemilu 2024 - Kaltim',
    'Draf kuesioner untuk Daerah Pemilihan Kalimantan Timur.',
    '[{"id": "q1", "text": "Berapa usia Bapak/Ibu/Saudara sekarang?", "description": "", "type": "radio", "options": ["17 \u2013 20 tahun", "21 \u2013 26 tahun", "27 \u2013 33 tahun", "34 \u2013 42 tahun", "43 \u2013 49 tahun", "50 \u2013 58 tahun", "59 \u2013 65 tahun", "Lebih dari 65 tahun"], "required": true, "conditions": []}, {"id": "q2", "text": "Kalau boleh tahu, apa tingkat pendidikan terakhir Bapak/Ibu/Saudara?", "description": "", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q3", "text": "Selain sebagai warga negara Indonesia, Bapak/Ibu/Saudara merasa sebagai suku bangsa apa?", "description": "", "type": "radio", "options": ["Bali", "Banjar", "Batak", "Berau", "Bugis", "Dayak", "Jawa", "Kutai", "Madura", "Mandar", "Melayu", "Menado", "Paser", "Tionghoa", "Toraja"], "required": true, "conditions": []}, {"id": "q4", "text": "Apa agama Bapak/Ibu/Saudara?", "description": "", "type": "radio", "options": ["Islam", "Protestan", "Katolik", "Hindu", "Budha", "Kong Hu Cu"], "required": true, "conditions": []}, {"id": "q5", "text": "Bila Islam, apakah bapak/ibu/ Saudara merasa sebagai orang NU, Muhammadiyah, Persis, Al Irsyad, atau apa?", "description": "[HANYA DITANYAKAN YANG MENJAWAB \u201cISLAM\u201d]", "type": "radio", "options": ["NU", "Muhammadiyah", "Persis", "Al Irsyad", "Tidak berafiliasi ke organisasi Islam apapun"], "required": true, "conditions": [{"questionId": "q4", "operator": "equals", "value": "Islam"}]}, {"id": "q6", "text": "Kalau boleh tahu, apa pekerjaan Bapak/Ibu/Saudara saat ini?", "description": "", "type": "radio", "options": ["Petani/ Nelayan", "Buruh/ Tukang (kayu/batu)", "Pedagang/ Wiraswasta kecil", "Pedagang besar/ Pengusaha", "Pengemudi (Ojek, Sopir Truk, dll)", "PNS/Pensiunan PNS", "Profesional (Dokter, Pengacara, dll)", "Pegawai swasta", "Purnawirawan TNI/Polri", "Ibu rumah tangga", "Masis Sekolah/ Mahasiswa", "Sedang mencari pekerjaan/ menganggur"], "required": true, "conditions": []}, {"id": "q7", "text": "Rata-rata dalam sebulan, kira\u2013kira berapa jumlah (dalam rupiah) Penghasilan Kotor \u201cRumah Tangga\u201d Bapak/Ibu/ Saudara?", "description": "", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q8", "text": "Seandainya Pemilu dilakukan hari ini, partai politik apa yang akan Bapak/Ibu/Saudara pilih? [JANGAN SEBUTKAN NAMA PARTAI POLITIK] Tulis nama partai politik,___________________________________", "description": "[TULIS HURUF KAPITAL DAN RAPI]", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q9", "text": "Jika pemilihan anggota legislatif/DPR RI (DPR Pusat) dilaksanakan hari ini, partai politik manakah yang Bapak/Ibu/Saudara pilih?", "description": "[TUNJUKAN KARTU BANTU 1, PARTAI POLITIK]", "type": "radio", "options": ["Partai Hati Nurani Rakyat (Hanura)", "Partai Garda Perubahan Indonesia (Garuda)", "Partai Amanat Nasional (PAN)", "Partai Bulan Bintang (PBB)", "Partai Demokrat", "Partai Solidaritas Indonesia (PSI)", "Partai Persatuan Indonesia (Perindo)", "Partai Persatuan Pembangunan (PPP)", "Partai Ummat", "Tidak Tahu/ Tidak Jawab [JANGAN DIBACAKAN]"], "required": true, "conditions": []}, {"id": "q10", "text": "Dari nama-nama calon Anggota legislatif/DPR RI (DPR Pusat) dari Partai, yang dipilih di Q9 pada Kartu Bantu 1,   nama siapakah yang akan Bapak/Ibu/Saudara pilih, jika pemilihan Anggota DPR RI Dapil Provinsi Kalimantan Timur dilaksanakan hari ini? Tulis nama calon legislatif/DPR RI,___________________________________[TULIS HURUF KAPITAL DAN RAPI] --- PAGE 5 --- 3", "description": "[TUNJUKAN KARTU BANTU 1, PARTAI POLITIK]", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q11", "text": "Jika pemilihan anggota DPRD Provinsi dilaksanakan hari ini, partai politik manakah yang Bapak/Ibu/Saudara pilih?", "description": "[TUNJUKAN KARTU BANTU 1, PARTAI POLITIK]", "type": "radio", "options": ["Partai Hati Nurani Rakyat (Hanura)", "Partai Garda Perubahan Indonesia (Garuda)", "Partai Amanat Nasional (PAN)", "Partai Bulan Bintang (PBB)", "Partai Demokrat", "Partai Solidaritas Indonesia (PSI)", "Partai Persatuan Indonesia (Perindo)", "Partai Persatuan Pembangunan (PPP)", "Partai Ummat", "Tidak Tahu/ Tidak Jawab [JANGAN DIBACAKAN]"], "required": true, "conditions": []}, {"id": "q12", "text": "Kalau boleh tahu, apa alasan utama Bapak/Ibu/Saudara memilih partai politik tersebut?, apakah karena\u2026.", "description": "[HANYA DITANYAKAN KEPADA RESPONDEN YANG \u201cMENJAWAB\u201d DI Q9]", "type": "radio", "options": ["Partai politik tersebut memperjuangkan/membela kepentingan agama Islam"], "required": true, "conditions": []}, {"id": "q13", "text": "Apa alasan paling utama Bapak/Ibu/Saudara memilih PKB? Apakah karena . . .", "description": "[HANYA DITANYAKAN BILA RESPONDEN MEMILIH PKB DI Q9]", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q14", "text": "Apa alasan paling utama Bapak/Ibu/Saudara memilih PARTAI GERINDRA? Apakah karena . . .", "description": "[HANYA DITANYAKAN BILA RESPONDEN MEMILIH PARTAI GERINDRA PADA Q9]", "type": "radio", "options": ["Gerindra mewakili aspirasi petani, nelayan, dan pedagang kaki lima (PKL)", "Tertarik figur Prabowo Subianto", "Tertarik figur/tokoh Partai Gerindra di Daerah", "Merasa puas terhadap kinerja para tokoh/kader Gerindra di pemerintahan pusat/daerah", "Tertarik program-program Partai Gerindra", "Tertarik slogan/tagline Partai Gerindra", "Sudah terbiasa memilih Partai Gerindra (loyalis)", "Partai Gerindra konsisten menjaga persatuan dan keberagaman"], "required": true, "conditions": []}, {"id": "q15", "text": "Apa alasan paling utama Bapak/Ibu/Saudara memilih PDI PERJUANGAN? Apakah karena . . .", "description": "[HANYA DITANYAKAN BILA RESPONDEN MEMILIH PDI PERJUANGAN DI Q9]", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q16", "text": "Apa alasan paling utama Bapak/Ibu/Saudara memilih PARTAI GOLKAR? Apakah karena . . .", "description": "[HANYA DITANYAKAN BILA RESPONDEN MEMILIH PARTAI GOLKAR DI Q9]", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q17", "text": "Apa alasan paling utama Bapak/Ibu/Saudara memilih Partai NasDem? Apakah karena . . .", "description": "[HANYA DITANYAKAN BILA RESPONDEN MEMILIH PARTAI NASDEM DI Q9]", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q18", "text": "Apa alasan paling utama Bapak/Ibu/Saudara memilih PKS? Apakah karena . . .", "description": "[HANYA DITANYAKAN BILA RESPONDEN MEMILIH PKS DI Q9]", "type": "radio", "options": ["Tertarik figur Salim Segaf Al Jufri", "Tertarik dukungan PKS terhadap pencapresan Anies Baswedan", "PKS mewakili aspirasi umat Islam", "Tertarik slogan/tagline PKS", "Tertarik figur/tokoh partai di daerah", "Tertarik program-program PKS", "Sudah terbiasa memilih PKS (loyalis)"], "required": true, "conditions": []}, {"id": "q19", "text": "Apa alasan paling utama Bapak/Ibu/Saudara memilih Partai Demokrat? Apakah karena . . .", "description": "[HANYA DITANYAKAN BILA RESPONDEN MEMILIH PARTAI DEMOKRAT DI Q9]", "type": "radio", "options": ["Tertarik figur Susilo Bambang Yudhoyono", "Tertarik figur Agus Harimurti Yudhoyono", "Tertarik dukungan Partai Demokrat terhadap pencapresan Anies Baswedan", "Tertarik figur/tokoh Partai Demokrat di daerah", "Tertarik program-program Partai Demokrat", "Sudah terbiasa memilih Partai Demokrat (loyalis)"], "required": true, "conditions": []}, {"id": "q20", "text": "Sebutkan satu nama anggota legislatif/DPR RI (DPR Pusat) periode 2019-2024 dari Daerah Pemilihan (Dapil) Provinsi Kalimantan Timur, yang Bapak/Ibu/Saudara ketahui? Tulis nama anggota DPR RI,_____________________________________________________________________________", "description": "[JANGAN SEBUTKAN NAMA ANGGOTA DPR RI]", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q21", "text": "Seandainya Pemilu dilakukan hari ini, siapa yang akan Bapak/Ibu/Saudara pilih sebagai Calon Anggota Legislatif/DPR RI (DPR Pusat)? Tulis nama calon legislatif,______________________________________________________________________________", "description": "[JANGAN SEBUTKAN NAMA KANDIDAT]", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q22", "text": "Dari nama-nama tokoh di bawah ini, apakah Bapak/Ibu/Saudara KENAL (pernah mendengar, membaca, atau melihat) atau TIDAK KENAL?, serta JIKA KENAL, SUKA atau TIDAK SUKA dengan tokoh tersebut? NO NAMA TOKOH KENAL TIDAK KENAL SUKA TIDAK SUKA 1 ADRI PRASETYO MARTOWARDOYO 1 2 1 2 2 AUS HIDAYAT NUR 1 2 1 2 3 AWANG FAROEK ISHAK 1 2 1 2 4 G BUDISATRIO DJIWANDONO 1 2 1 2 5 HADI MULYADI 1 2 1 2 6 HETIFAH SJAIFUDIAN 1 2 1 2 7 IRWAN FECHO 1 2 1 2 8 ISMAIL THOMAS 1 2 1 2 9 NABIL HUSEIN 1 2 1 2 10 RIZAL EFFENDI 1 2 1 2 11 RUDY MAS\u2019UD 1 2 1 2 12 SAFARUDDIN 1 2 1 2 13 SYAFRUDDIN 1 2 1 2 14 SYARIFAH SURAIDAH ABIDIN 1 2 1 2", "description": "", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q23", "text": "Dari nama-nama tokoh di bawah ini, siapakah yang paling dikenal oleh Bapak/Ibu/Saudara?", "description": "", "type": "radio", "options": ["RIZAL EFFENDI", "RUDY MAS\u2019UD", "SAFARUDDIN", "SYAFRUDDIN", "SYARIFAH SURAIDAH ABIDIN", "TIDAK TAHU/ TIDAK JAWAB [JANGAN"], "required": true, "conditions": []}, {"id": "q24", "text": "Jika kenal (Q22), dengan nama-nama anggota DPR RI Dapil Provinsi Kalimantan Timur di bawah ini, apakah Bapak/Ibu/Saudara PUAS atau TIDAK PUAS dengan kinerja anggota DPR RI tersebut? NO NAMA ANGGOTA DPR RI PUAS TIDAK PUAS 1 AUS HIDAYAT NUR 1 2 2 AWANG FAROEK ISHAK 1 2 3 G BUDISATRIO DJIWANDONO 1 2 4 HETIFAH SJAIFUDIAN 1 2 5 IRWAN FECHO 1 2 6 ISMAIL THOMAS 1 2 7 RUDI MAS\u2019UD 1 2 8 SAFARUDDIN 1 2 --- PAGE 8 --- 6", "description": "", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q25", "text": "Diantara nama-nama anggota DPR RI dari Dapil Provinsi Kalimantan Timur dibawah ini, dengan siapakah yang Bapak/Ibu/Saudara merasa paling mengenal dan atau memiliki kedekatan?", "description": "", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q26", "text": "Diantara nama-nama anggota DPR RI dari Dapil Provinsi Kalimantan Timur dibawah ini, manakah yang pernah berdiskusi dan berkomunikasi dengan Bapak/Ibu/Saudara terkait kebijakan-kebijakan Pemerintah?", "description": "", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q27", "text": "Diantara nama-nama anggota DPR RI dari Dapil Provinsi Kalimantan Timur dibawah ini, siapakah yang menurut Bapak/Ibu/Saudara memberikan perhatian lebih terhadap pembangunan infrastruktur (jalan, jembatan, parit, air bersih, listrik, dll) bagi kepentingan masyarakat?", "description": "", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q28", "text": "Diantara nama-nama anggota DPR RI dari Dapil Provinsi Kalimantan Timur dibawah ini, siapakah yang menurut Bapak/Ibu/Saudara memberikan perhatian lebih terhadap sektor pertanian, peternakan dan perikanan (Alat dan mesin pertanian, bantuan bibit/pupuk, sarana peternakan sarana perikanan, peralatan nelayan, dll) bagi kepentingan masyarakat?", "description": "", "type": "radio", "options": ["AUS HIDAYAT NUR", "AWANG FAROEK ISHAK", "G BUDISATRIO DJIWANDONO", "HETIFAH SJAIFUDIAN", "IRWAN FECHO", "ISMAIL THOMAS", "RUDI MAS\u2019UD", "SAFARUDDIN", "TIDAK TAHU/ TIDAK JAWAB [JANGAN"], "required": true, "conditions": []}, {"id": "q29", "text": "Diantara nama-nama anggota DPR RI dari Dapil Provinsi Kalimantan Timur dibawah ini, siapakah yang menurut Bapak/Ibu/Saudara memberikan perhatian lebih terhadap sektor pendidikan (beasiswa, bantuan seragam/sepatu sekolah, pembangunan/perbaikan sarana Pendidikan, dll) bagi kepentingan masyarakat?", "description": "", "type": "radio", "options": ["AUS HIDAYAT NUR", "AWANG FAROEK ISHAK", "G BUDISATRIO DJIWANDONO", "HETIFAH SJAIFUDIAN", "IRWAN FECHO", "ISMAIL THOMAS", "RUDI MAS\u2019UD", "SAFARUDDIN", "TIDAK TAHU/ TIDAK JAWAB [JANGAN"], "required": true, "conditions": []}, {"id": "q30", "text": "Diantara nama-nama anggota DPR RI dari Dapil Provinsi Kalimantan Timur dibawah ini, siapakah yang menurut Bapak/Ibu/Saudara memberikan perhatian lebih terhadap sektor kesehatan (bantuan berobat/cek kesehatan gratis, bantuan ambulance, pembangunan sarana prasarana kesehatan daerah, dll) bagi kepentingan masyarakat?", "description": "", "type": "radio", "options": ["AUS HIDAYAT NUR", "AWANG FAROEK ISHAK", "G BUDISATRIO DJIWANDONO", "HETIFAH SJAIFUDIAN", "IRWAN FECHO", "ISMAIL THOMAS", "RUDI MAS\u2019UD", "SAFARUDDIN", "TIDAK TAHU/ TIDAK JAWAB [JANGAN"], "required": true, "conditions": []}, {"id": "q31", "text": "Diantara nama-nama anggota DPR RI dari Dapil Provinsi Kalimantan Timur dibawah ini, siapakah yang menurut Bapak/Ibu/Saudara memberikan perhatian lebih terhadap sektor keagamaan dan sosial kemanusiaan (bantuan pembangunan/renovasi tempat ibadah, hewan qurban, bantuan pandemi Covid, bantuan sembako bencana alam) bagi kepentingan masyarakat?", "description": "", "type": "radio", "options": ["AUS HIDAYAT NUR", "AWANG FAROEK ISHAK", "G BUDISATRIO DJIWANDONO", "HETIFAH SJAIFUDIAN", "IRWAN FECHO", "ISMAIL THOMAS", "RUDI MAS\u2019UD", "SAFARUDDIN", "TIDAK TAHU/ TIDAK JAWAB [JANGAN"], "required": true, "conditions": []}, {"id": "q32", "text": "Diantara nama-nama anggota DPR RI dari Dapil Provinsi Kalimantan Timur dibawah ini, siapakah yang menurut Bapak/Ibu/Saudara memberikan perhatian lebih terhadap sektor Perdagangan dan UMKM (sarana dagang, pelatihan/peralatan bagi UMKM, modal bagi UMKM, bantuan pemasaran, dll) bagi kepentingan masyarakat?", "description": "", "type": "radio", "options": ["AUS HIDAYAT NUR", "AWANG FAROEK ISHAK", "G BUDISATRIO DJIWANDONO", "HETIFAH SJAIFUDIAN", "IRWAN FECHO", "ISMAIL THOMAS", "RUDI MAS\u2019UD", "SAFARUDDIN", "TIDAK TAHU/ TIDAK JAWAB [JANGAN"], "required": true, "conditions": []}, {"id": "q33", "text": "Diantara nama-nama anggota DPR RI dari Dapil Provinsi Kalimantan Timur dibawah ini, siapakah yang menurut Bapak/Ibu/Saudara paling sering memberikan bantuan berupa bahan-bahan pokok (sembako)?", "description": "", "type": "radio", "options": ["AUS HIDAYAT NUR", "AWANG FAROEK ISHAK", "G BUDISATRIO DJIWANDONO", "HETIFAH SJAIFUDIAN", "IRWAN FECHO", "ISMAIL THOMAS", "RUDI MAS\u2019UD", "SAFARUDDIN", "TIDAK TAHU/ TIDAK JAWAB [JANGAN"], "required": true, "conditions": []}, {"id": "q34", "text": "Diantara nama-nama anggota DPR RI dari Dapil Provinsi Kalimantan Timur dibawah ini, dengan siapakah Bapak/Ibu/Saudara pernah berinteraksi atau menyampaikan aspirasi. Baik secara langsung kepada Anggota DPR RI, datang ke rumah aspirasi Anggota DPR RI, melalui tim Dapil/staf Anggota DPR RI, maupun melalui sarana lain seperti telepon, SMS, Media Sosial (Whatsapp, Facebook, Twitter, Instagram dll) dan website?\u201d", "description": "", "type": "radio", "options": ["AUS HIDAYAT NUR", "AWANG FAROEK ISHAK", "G BUDISATRIO DJIWANDONO", "HETIFAH SJAIFUDIAN", "IRWAN FECHO", "ISMAIL THOMAS", "RUDI MAS\u2019UD", "SAFARUDDIN", "TIDAK TAHU/ TIDAK JAWAB [JANGAN"], "required": true, "conditions": []}, {"id": "q35", "text": "Siapakah yang Bapak/Ibu/Saudara pilih pada pemilihan umum legislatif 2019 (DPR) dari Dapil Provinsi Kalimantan Timur?", "description": "", "type": "radio", "options": ["AUS HIDAYAT NUR", "AWANG FAROEK ISHAK", "G BUDISATRIO DJIWANDONO", "HETIFAH SJAIFUDIAN", "IRWAN FECHO", "ISMAIL THOMAS", "RUDI MAS\u2019UD", "SAFARUDDIN", "TIDAK TAHU/ TIDAK JAWAB [JANGAN"], "required": true, "conditions": []}, {"id": "q36", "text": "Apakah Bapak/Ibu/Saudara masih MENGINGINKAN atau TIDAK MENGINGINKAN nama-nama dibawah ini terpilih kembali sebagai anggota legislatif (DPR RI) mewakili Dapil Provinsi Kalimantan Timur? NO NAMA TOKOH YA, MENGINGINKAN TIDAK MENGINGINKAN 1 AUS HIDAYAT NUR 1 2 2 AWANG FAROEK ISHAK 1 2 3 G BUDISATRIO DJIWANDONO 1 2 4 HETIFAH SJAIFUDIAN 1 2 5 IRWAN FECHO 1 2 6 ISMAIL THOMAS 1 2 7 RUDI MAS\u2019UD 1 2 8 SAFARUDDIN 1 2 --- PAGE 10 --- 8", "description": "", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q37", "text": "Seandainya pemilihan Anggota DPR RI Dapil Provinsi Kalimantan Timur dilaksanakan hari ini, siapakah yang Bapak/Ibu/Saudara pilih dari nama-nama di bawah ini?", "description": "", "type": "radio", "options": ["ADRI PRASETYO MARTOWARDOYO", "AUS HIDAYAT NUR", "AWANG FAROEK ISHAK", "G BUDISATRIO DJIWANDONO", "HADI MULYADI", "HETIFAH SJAIFUDIAN", "IRWAN FECHO", "ISMAIL THOMAS", "NABIL HUSEIN", "RIZAL EFFENDI", "RUDY MAS\u2019UD", "SAFARUDDIN", "SYAFRUDDIN", "SYARIFAH SURAIDAH ABIDIN", "TIDAK TAHU/ TIDAK JAWAB [JANGAN"], "required": true, "conditions": []}, {"id": "q38", "text": "Sebutkan satu nama calon anggota DPD RI periode 2019-2024 dari Daerah Pemilihan (Dapil) Provinsi Kalimantan Timur, yang Bapak/Ibu/Saudara ketahui? Tulis nama anggota DPD RI,_____________________________________________________________________________", "description": "[JANGAN SEBUTKAN NAMA ANGGOTA DPD RI]", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q39", "text": "Seandainya Pemilu dilakukan hari ini, siapa yang akan Bapak/Ibu/Saudara pilih sebagai Calon Anggota DPD RI Daerah Pemilihan (Dapil) Provinsi Kalimantan Timur? Tulis nama calon legislatif,______________________________________________________________________________", "description": "[JANGAN SEBUTKAN NAMA KANDIDAT]", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q40", "text": "Siapakah yang Bapak/Ibu/Saudara pilih pada pemilihan umum legislatif 2019 (DPD) dari Dapil Provinsi Kalimantan Timur?", "description": "", "type": "radio", "options": ["AJI MIRNI MAWARNI", "MAHYUDIN", "NANANG SULAIMAN", "ZAINAL ARIFIN", "TIDAK TAHU/ TIDAK JAWAB [JANGAN"], "required": true, "conditions": []}, {"id": "q41", "text": "Apakah Bapak/Ibu/Saudara masih MENGINGINKAN atau TIDAK MENGINGINKAN nama-nama dibawah ini terpilih kembali sebagai anggota DPD RI mewakili Dapil Provinsi Kalimantan Timur? NO NAMA TOKOH YA, MENGINGINKAN TIDAK MENGINGINKAN 1 AJI MIRNI MAWARNI 1 2 2 MAHYUDIN 1 2 3 NANANG SULAIMAN 1 2 4 ZAINAL ARIFIN 1 2", "description": "", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q42", "text": "Seandainya pemilihan Anggota DPD RI Dapil Provinsi Kalimantan Timur dilaksanakan hari ini, siapakah yang Bapak/Ibu/Saudara pilih dari nama-nama di bawah ini?", "description": "", "type": "radio", "options": ["AJI MIRNI MAWARNI", "MAHYUDIN", "NANANG SULAIMAN", "ZAINAL ARIFIN", "EMIR MOEIS", "HABIB AHMAD BAHASYIM", "ANDI SOFYAN HASDAM", "ABDUL JAWAD", "YULIANUS HENOCK SUMUAL,", "RENDI SUSISWO", "NASPI ARSYAD", "TIDAK TAHU/ TIDAK JAWAB [JANGAN"], "required": true, "conditions": []}, {"id": "q43", "text": "Apakah pilihan Bapak/Ibu/Saudara terhadap calon Anggota DPR RI daerah pemilihan Provinsi Kalimantan Timur, sudah mantap atau masih mungkin berubah?", "description": "", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q44", "text": "Apabila pilihan Bapak/Ibu/Saudara masih mungkin berubah, apakah yang menyebabkan pilihan Bapak/Ibu/Saudara berubah?", "description": "[HANYA DITANYAKAN KEPADA RESPONDEN YANG MENJAWAB \u201cMASIH MUNGKIN BERUBAH\u201d]", "type": "text", "options": [], "required": true, "conditions": [{"questionId": "q43", "operator": "equals", "value": "Masih mungkin berubah"}]}, {"id": "q45", "text": "Kapan kira-kira Bapak/Ibu/Saudara sudah benar-benar mantap dalam menentukan pilihan calon DPR RI Dapil Provinsi Kalimantan Timur?", "description": "", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q46", "text": "Apa alasan yang membuat Bapak/Ibu menjatuhkan pilihan pada nama-nama tokoh di atas?", "description": "", "type": "radio", "options": ["Orangnya jujur/bebas KKN", "Orangnya tegas", "Orangnya pintar/berpendidikan", "Sudah ada bukti nyata hasil kerjanya", "Tokoh agama", "Tokoh partai politik"], "required": true, "conditions": []}, {"id": "q47", "text": "Program apa yang harus dilakukan oleh calon anggota legislatif (DPR RI) sehingga dipilih oleh masyarakat di daerah Bapak/Ibu/Saudara?", "description": "", "type": "radio", "options": ["Biaya Pendidikan Murah", "Melakukan pendekata/perhatian dengan rakyat", "Memberantas Korupsi", "Membuat Undang-Undang yang sesuai dengan kondisi masyarakat", "Membuat/memperbaiki jalan", "Menciptakan lapangan kerja", "Mensejahterakan rakyat", "Menurunkan harga sembako", "Menyediakan air bersih", "Menyediakan fasilitas dan sarana kesehatan", "Partai Politiknya mengusung calon Presiden yang saya sukai"], "required": true, "conditions": []}, {"id": "q48", "text": "Menurut Bapak/ibu/Saudara, manakah kriteria dibawah ini yang sangat penting dan tidak penting dimiliki calon anggota legislatif (DPR RI)? NO KRITERIA PENTING TIDAK PENTING 1 Kemampuan membuat Undang-Undang 1 2 2 Kemampuan mengawasi kinerja pemerintahan 1 2 3 Dapat dipercaya, jujur dan tidak korupsi 1 2 4 Penampilan fisik (pakaian rapi, cantik dan ganteng) 1 2 5 Gaya bicara dan Perilaku yang baik (Sopan, santun dan bicara mudah dimengerti) 1 2 6 Program yang jelas dan bermanfaat (pasar murah, perbaikan jalan, pembangunan tempat ibadah, dll) 1 2 7 Memiliki latar belakang yang sama (agama, suku, asal daerah) 1 2 8 Memiliki kompetensi di bidang tertentu/Pintar 1 2", "description": "", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q49", "text": "Menurut Bapak/Ibu/Saudara, berdasarkan latar belakang asal calon anggota DPR RI, apakah anda menyukai calon yang berasal dari Putra Daerah atau Bukan Putra Daerah?", "description": "", "type": "radio", "options": ["Putra Daerah", "Bukan Putra Daerah", "Sama saja"], "required": true, "conditions": []}, {"id": "q50", "text": "Ada sejumlah sifat kepemimpinan yang harus dimiliki oleh seorang calon anggota DPR RI. Di antara sifat kepemimpinan di bawah ini manakah yang paling penting dimiliki oleh seorang calon anggota DPR RI Dapil Provinsi Kalimantan Timur?", "description": "", "type": "radio", "options": ["Berwibawa", "Bisa dipercaya", "Bersih dari korupsi", "Enak dipandang/ganteng/cantik", "Menyenangkan, ramah dan hangat", "Perhatian pada rakyat", "Pintar atau berwawasan luas", "Tegas", "Tidak cacat moral"], "required": true, "conditions": []}, {"id": "q51", "text": "Di antara tokoh-tokoh masyarakat dibawah ini, siapa yang paling berpengaruh terhadap pilihat politik Bapak/Ibu/Saudara?", "description": "", "type": "radio", "options": ["Tokoh agama", "Tokoh adat", "Tokoh Pemuda", "Pengusaha", "Guru", "Pengurus Partai", "Camat", "Kepala Desa", "Ketua/Ibu-ibu PKK", "Tim Kampanye"], "required": true, "conditions": []}, {"id": "q52", "text": "Apakah faktor agama menjadi pertimbangan utama Bapak/Ibu/Saudara dalam memilih Calon Anggota DPR RI dan Presiden?", "description": "", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q53", "text": "Apakah faktor uang menjadi pertimbangan utama Bapak/Ibu/Saudara dalam memilih Calon Anggota DPR RI dan Presiden?", "description": "", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q54", "text": "Apakah Bapak/Ibu/Saudara lebih memilih dikasih hadiah berupa uang atau barang untuk memberikan dukungan kepada calon legislatif (DPR RI) tertentu?", "description": "", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q55", "text": "Bentuk sumbangan/hadiah/kenang-kenangan apa yang paling Bapak/Ibu/Saudara sukai dari calon Anggota Legislatif (DPR RI, DPRD Provinsi, DPRD Kab/Kota)?", "description": "", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q56", "text": "Jika saat pemilihan legislatif 14 Februari 2024 mendatang, ada calon legislatif (DPR RI/DPRD) tertentu memberi anda uang, apakah Bapak/Ibu/Saudara akan menerima atau tidak menerima pemberian uang tersebut?", "description": "", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q57", "text": "Menurut Bapak/Ibu/Saudara berapakah besaran nominal uang yang pantas/layak diberikan Calon Legislatif (DPR RI/DPRD) saat pemilihan umum? Tulis besaran nominal, ___________________________________[TULIS HURUF KAPITAL DAN RAPI]", "description": "[HANYA DITANYAKAN KEPADA RESPONDEN YANG MENJAWAB \u201cMENERIMA\u201d]", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q58", "text": "Pada pemilihan legislatif 2019 yang lalu, Apakah Bapak/Ibu/Saudara pernah menerima atau tidak menerima uang dari orang/tim sukses untuk memilih salah satu calon anggota DPR RI?", "description": "", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q59", "text": "Bagaimana sikap Bapak/Ibu/Saudara bila ada seseorang yang memberikan politik uang saat pemilihan umum?", "description": "", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q60", "text": "Jika ada orang/tim sukses memberi Bapak/Ibu/Saudara uang, yang bermaksud untuk memilih salah satu calon anggota DPR RI, berapakah besaran nominal uang yang pantas untuk diberikan?", "description": "", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q61", "text": "Seandainya Pemilihan Gubernur Kalimantan Timur dilakukan hari ini, siapa yang akan Bapak/Ibu/Saudara pilih sebagai Gubernur? Tulis nama kandidat pilihan, ___________________________________[TULIS HURUF KAPITAL DAN RAPI] --- PAGE 14 --- 12", "description": "[JANGAN   SEBUTKAN NAMA KANDIDAT]", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q62", "text": "Dari nama-nama tokoh di bawah ini, apakah Bapak/Ibu/Saudara KENAL (pernah mendengar, membaca, atau melihat) atau TIDAK KENAL?, serta JIKA KENAL, SUKA atau TIDAK SUKA dengan tokoh tersebut? NO NAMA TOKOH KENAL TIDAK KENAL SUKA TIDAK SUKA 1 ANDI HARUN 1 2 1 2 2 ANDI SOFYAN HASDAM 1 2 1 2 3 ARDIANSYAH SULAIMAN 1 2 1 2 4 AWANG FERDIAN HIDAYAT 1 2 1 2 5 BASRI RASE 1 2 1 2 6 EDI DAMANSYAH 1 2 1 2 7 FAHMI FADLI 1 2 1 2 8 HADI MULYADI 1 2 1 2 9 IRWAN FECHO 1 2 1 2 10 ISRAN NOOR 1 2 1 2 11 RIZAL EFFENDI 1 2 1 2 12 RUDI MAS\u2019UD 1 2 1 2 13 RUSMADI 1 2 1 2 14 SAFARUDDIN 1 2 1 2 15 SYAHARIE JAANG 1 2 1 2", "description": "", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q63", "text": "Seandainya Pemilihan Gubernur Kalimantan Timur dilaksanakan hari ini, siapakah yang akan Bapak/Ibu/Saudara pilih dari nama-nama di bawah ini?", "description": "[HANYA SATU JAWABAN]", "type": "radio", "options": ["ANDI HARUN", "ANDI SOFYAN HASDAM", "ARDIANSYAH SULAIMAN", "AWANG FERDIAN HIDAYAT", "BASRI RASE", "EDI DAMANSYAH", "FAHMI FADLI", "HADI MULYADI", "IRWAN FECHO", "ISRAN NOOR", "RIZAL EFFENDI", "RUDI MAS\u2019UD", "RUSMADI", "SAFARUDDIN", "SYAHARIE JAANG", "TIDAK TAHU/TIDAK [JANGAN DIBACAKAN]"], "required": true, "conditions": []}, {"id": "q64", "text": "Seandainya Pemilihan Gubernur Kalimantan Timur dilaksanakan hari ini, siapakah yang akan Bapak/Ibu/Saudara pilih dari nama-nama di bawah ini?", "description": "[HANYA SATU JAWABAN]", "type": "radio", "options": ["TIDAK TAHU/TIDAK [JANGAN DIBACAKAN]"], "required": true, "conditions": []}, {"id": "q65", "text": "Seandainya Pemilihan Gubernur Kalimantan Timur dilaksanakan hari ini, siapakah yang akan Bapak/Ibu/Saudara pilih dari nama-nama di bawah ini?", "description": "[HANYA SATU JAWABAN]", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q66", "text": "Seandainya Pemilihan Gubernur Kalimantan Timur dilaksanakan hari ini, siapakah yang akan Bapak/Ibu/Saudara pilih dari nama-nama di bawah ini?", "description": "[HANYA SATU JAWABAN]", "type": "radio", "options": ["ANDI HARUN", "ISRAN NOOR", "RUDI MAS\u2019UD", "TIDAK TAHU/TIDAK [JANGAN DIBACAKAN]"], "required": true, "conditions": []}, {"id": "q67", "text": "Seandainya Pemilihan Gubernur Kalimantan Timur dilaksanakan hari ini, siapakah yang akan Bapak/Ibu/Saudara pilih dari nama-nama di bawah ini?", "description": "[HANYA SATU JAWABAN]", "type": "radio", "options": ["ANDI HARUN", "ISRAN NOOR", "TIDAK TAHU/TIDAK [JANGAN DIBACAKAN]"], "required": true, "conditions": []}, {"id": "q68", "text": "Seandainya Pemilihan Gubernur Kalimantan Timur dilaksanakan hari ini, siapakah yang akan Bapak/Ibu/Saudara pilih dari nama-nama di bawah ini?", "description": "[HANYA SATU JAWABAN]", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q69", "text": "Seandainya Pemilihan Gubernur Kalimantan Timur dilaksanakan hari ini, siapakah yang akan Bapak/Ibu/Saudara pilih dari nama-nama di bawah ini?", "description": "[HANYA SATU JAWABAN]", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q70", "text": "Seandainya Pemilihan Presiden dilakukan hari ini, siapa yang akan Bapak/Ibu/Saudara pilih sebagai Presiden RI? Tulis nama kandidat pilihan, ___________________________________[TULIS HURUF KAPITAL DAN RAPI]", "description": "[JANGAN   SEBUTKAN NAMA KANDIDAT]", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q71", "text": "Seandainya Pemilihan Presiden dilaksanakan hari ini, siapakah yang akan Bapak/Ibu/Saudara pilih dari nama- nama di bawah ini?", "description": "[HANYA SATU JAWABAN]", "type": "radio", "options": ["A. MUHAIMIN ISKANDAR", "AIRLANGGA HARTARTO", "ANIES R. BASWEDAN", "GANJAR PRANOWO", "PRABOWO SUBIANTO", "TIDAK TAHU/TIDAK [JANGAN DIBACAKAN]"], "required": true, "conditions": []}, {"id": "q72", "text": "Seandainya Pemilihan Presiden dilaksanakan hari ini, siapakah yang akan Bapak/Ibu/Saudara pilih dari nama- nama di bawah ini?", "description": "[HANYA SATU JAWABAN]", "type": "radio", "options": ["ANIES R. BASWEDAN", "GANJAR PRANOWO", "PRABOWO SUBIANTO", "TIDAK TAHU/TIDAK [JANGAN DIBACAKAN]"], "required": true, "conditions": []}, {"id": "q73", "text": "Siapa yang akan Bapak/Ibu/Saudara pilih sebagai Presiden jika pemilihan dilaksanakan hari ini, dan hanya dua nama berikut yang maju sebagai calon Presiden?", "description": "[HANYA SATU JAWABAN]", "type": "radio", "options": ["ANIES R. BASWEDAN", "GANJAR PRANOWO", "TIDAK TAHU/TIDAK JAWAB [JANGAN DIBACAKAN]"], "required": true, "conditions": []}, {"id": "q74", "text": "Siapa yang akan Bapak/Ibu/Saudara pilih sebagai Presiden jika pemilihan dilaksanakan hari ini, dan hanya dua nama berikut yang maju sebagai calon Presiden?", "description": "[HANYA SATU JAWABAN]", "type": "radio", "options": ["ANIES R. BASWEDAN", "PRABOWO SUBIANTO", "TIDAK TAHU/TIDAK [JANGAN DIBACAKAN]"], "required": true, "conditions": []}, {"id": "q75", "text": "Siapa yang akan Bapak/Ibu/Saudara pilih sebagai Presiden jika pemilihan dilaksanakan hari ini, dan hanya dua nama berikut yang maju sebagai calon Presiden?", "description": "[HANYA SATU JAWABAN]", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q76", "text": "Jika pemilihan presiden-wakil presiden diadakan sekarang, siapa yang akan Bapak/Ibu/Saudara pilih sebagai Wakil Presiden di antara nama-nama berikut ini? AGUS HARIMURTI YUDHOYONO", "description": "[JANGAN DIBACAKAN]", "type": "radio", "options": ["TT/TJ"], "required": true, "conditions": []}, {"id": "q77", "text": "Seandainya pemilihan Presiden dan Wakil Presiden dilaksanakan hari ini, pasangan manakah yang akan Bapak/Ibu/Saudara pilih?", "description": "[JANGAN DIBACAKAN]", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q78", "text": "Seandainya pemilihan Presiden dan Wakil Presiden dilaksanakan hari ini, pasangan manakah yang akan Bapak/Ibu/Saudara pilih?", "description": "[JANGAN DIBACAKAN]", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q79", "text": "Seandainya pemilihan Presiden dan Wakil Presiden dilaksanakan hari ini, pasangan manakah yang akan Bapak/Ibu/Saudara pilih?", "description": "[JANGAN DIBACAKAN]", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q80", "text": "Seandainya pemilihan Presiden dan Wakil Presiden dilaksanakan hari ini, pasangan manakah yang akan Bapak/Ibu/Saudara pilih?", "description": "[JANGAN DIBACAKAN]", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q81", "text": "Apakah Bapak/Ibu/Saudara sudah mengetahui bahwa pada 14 Februari 2024 akan dilaksanakan pemilihan Anggota Legislatif (DPRD Kabupaten/Kota, DPRD Provinsi, DPR RI dan DPD RI) dan Pemilihan Presiden- Wakil Presiden?", "description": "", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q82", "text": "Apakah Bapak/Ibu/Saudara akan ikut mencoblos atau memilih pada pemilihan Anggota Legislatif (DPRD Kabupaten/Kota, DPRD Provinsi, DPR RI dan DPD RI) dan Pemilihan Presiden-Wakil Presiden pada tahun 2024 yang akan datang?", "description": "[JANGAN DIBACAKAN]", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q83", "text": "Apakah Bapak/Ibu/Saudara sudah mengetahui bahwa pada 27 November 2024 akan dilaksanakan pemilihan Kepala Daerah (Bupati-Wakil Bupati, Walikota-Wakil Walikota dan Gubernur-Wakil Gubernur) secara serentak?", "description": "", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q84", "text": "Apakah Bapak/Ibu/Saudara akan ikut mencoblos atau memilih pada pemilihan Kepala Daerah tahun 2024 (Bupati-Wakil Bupati, Walikota-Wakil Walikota dan Gubernur-Wakil Gubernur) secara serentak yang akan datang?", "description": "[JANGAN DIBACAKAN]", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q85", "text": "Jika pada pemilihan umum legislatif (DPR RI) 2024 mendatang ikut mencoblos, manakah yang Bapak/Ibu/Saudara coblos pada kertas suara?", "description": "", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q86", "text": "Apakah Bapak/ Ibu/ Saudara sering membaca koran?", "description": "", "type": "radio", "options": ["Sangat sering (setiap hari)", "Cukup sering (2-3 hari sekali)", "Jarang (seminggu sekali)", "Sangat jarang (lebih dari seminggu sekali)", "Tidak pernah (tidak pernah sama sekali)"], "required": true, "conditions": []}, {"id": "q87", "text": "Koran apa yang sering Bapak/Ibu/Saudara baca?", "description": "[SEBUTKAN]", "type": "radio", "options": ["Kaltim Post", "Koran Balikpapan", "Koran Kaltim", "Poskota Kaltim", "Post Metro Balikpapan", "Samarinda Post", "Surat Kabar Harian Koran Kaltim", "Tribunnews", "Kaltim Today"], "required": true, "conditions": []}, {"id": "q88", "text": "Apakah Bapak/ Ibu/ Saudara sering menonton televisi?", "description": "", "type": "radio", "options": ["Sangat sering (setiap hari)", "Cukup sering (2-3 hari sekali)", "Jarang (seminggu sekali)", "Sangat jarang (lebih dari seminggu sekali)", "Tidak pernah (tidak pernah sama sekali)"], "required": true, "conditions": []}, {"id": "q89", "text": "Dalam 3 (tiga) bulan terakhir stasiun televisi apa yang sering Bapak/Ibu/Saudara tonton?", "description": "[SEBUTKAN]", "type": "radio", "options": ["ANTV", "GLOBAL TV", "TVRI KALIMANTAN TIMUR", "KALTIM TV", "INEWS TENGGARONG", "MAHAKAM CHANNEL", "VTV SAMARINDA", "GARUDA TV BALIKPAPAN", "BALIKPAPAN TV", "METRO TV BALIKPAPAN", "TVONE SAMARINDA", "BERAU TV"], "required": true, "conditions": []}, {"id": "q90", "text": "Program/Acara Televisi apa yang paling Bapak/Ibu/Saudara gemari? Tulis Nama Program/Acara, __________________________________________", "description": "[SEBUTKAN]", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q91", "text": "Pada jam berapa Bapak/Ibu/Saudara biasa menonton TV? Tulis waktu, ____________________________________________________________", "description": "[SEBUTKAN]", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q92", "text": "Apakah Bapak/Ibu/Saudara sering mendengarkan radio?", "description": "", "type": "text", "options": [], "required": true, "conditions": []}, {"id": "q93", "text": "Dalam 3 (tiga) bulan terakhir, radio apa yang sering Bapak/Ibu/Saudara dengar? Radio Gemaya", "description": "[SEBUTKAN]", "type"